data.css:
.stopwatch-container {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 100%;
  background: linear-gradient(135deg, #1e293b 0%, #0f172a 100%);
  color: #fff;
  border-radius: 8px;
  font-family: 'Monaco', 'Consolas', monospace;
}

.sw-title {
  font-size: 12px;
  color: #94a3b8;
  margin-bottom: 5px;
  text-transform: uppercase;
  letter-spacing: 1px;
}

.sw-time {
  font-size: 32px;
  font-weight: 700;
  margin-bottom: 15px;
  color: #38bdf8;
  text-shadow: 0 0 10px rgba(56, 189, 248, 0.3);
}

.sw-controls {
  display: flex;
  gap: 8px;
}

.sw-btn {
  border: none;
  padding: 6px 14px;
  border-radius: 6px;
  font-size: 12px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.2s;
  color: white;
}

.sw-btn:hover {
  transform: translateY(-1px);
  filter: brightness(1.1);
}

.sw-btn:active {
  transform: translateY(0);
}

.start { background: #10b981; box-shadow: 0 4px 6px -1px rgba(16, 185, 129, 0.3); }
.pause { background: #f59e0b; box-shadow: 0 4px 6px -1px rgba(245, 158, 11, 0.3); }
.reset { background: #ef4444; box-shadow: 0 4px 6px -1px rgba(239, 68, 68, 0.3); }
